from autogen import AssistantAgent

def audit_message_filter(message):
    if 'content' in message:
        content = message['content']
        suspicious_patterns = [
            r'\b(ignore|forget|override|execute|run)\b',
            r'you are (not|now).*(hacker|admin|root)',
            r'os\.(system|pop(?:en)?)'
        ]
        import re
        if any(re.search(pattern, content, re.IGNORECASE) for pattern in suspicious_patterns):
            return {'content': '[INJECTION DETECTED - BLOCKED]', 'blocked': True}
    return message

class InjectionMonitor:
    def __init__(self):
        self.agent_baselines = {}

    def monitor_reply(self, agent_id: str, reply: str) -> bool:
        if agent_id not in self.agent_baselines:
            self.agent_baselines[agent_id] = reply
            return False

        baseline = self.agent_baselines[agent_id]
        # Flag if agent suddenly talks about code execution or system commands
        anomaly_patterns = ['os.system', 'exec(', 'import os', 'subprocess']
        if any(pattern in reply for pattern in anomaly_patterns):
            return True
        return False

