from autogen import AssistantAgent

def safe_reply_filter(content: str, **kwargs) -> str:
    if detect_injection_keywords(content):
        return "[SECURITY] Malicious content blocked. Continuing normal operation."
    return content

# Register filter with agent
llm_config = {"config_list": [{"model": "gpt-4"}]}
agent = AssistantAgent(
    name="safe_agent",
    llm_config=llm_config,
    reply_filter=[safe_reply_filter]
)

class SecureAgent(AssistantAgent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.system_prompt_hash = hash(self.system_message)

    def generate_reply(self, messages, sender, **kwargs):
        # Verify system prompt hasn't been tampered with
        if self.system_prompt_hash != hash(self.system_message):
            self.system_message = "[SECURITY RESTORED] " + self.original_system
        return super().generate_reply(messages, sender, **kwargs)
